import boto3
import sys
from botocore.exceptions import ClientError

def create_sns_subscription(topic_arn, endpoint):
    try:
        sns = boto3.client('sns')
        response = sns.subscribe(
            TopicArn=topic_arn,
            Protocol='https',
            Endpoint=endpoint
        )
        return response
    except ClientError as e:
        print(f"Error creating subscription: {e}")
        return None

def main():
    if len(sys.argv) != 2:
        print("Usage: python script.py <topic_arn>")
        sys.exit(1)
    
    topic_arn = sys.argv[1]
    
    print("Enter subscription endpoints (press Enter twice to finish):")
    endpoints = []
    
    while True:
        try:
            endpoint = input().strip()
            if not endpoint:
                break
            endpoints.append(endpoint)
        except KeyboardInterrupt:
            break
        except EOFError:
            break
    
    if not endpoints:
        print("No endpoints provided.")
        sys.exit(1)
    
    for endpoint in endpoints:
        print(f"Creating subscription for: {endpoint}")
        result = create_sns_subscription(topic_arn, endpoint)
        if result:
            print(f"Subscription created successfully. SubscriptionArn: {result['SubscriptionArn']}")
        else:
            print(f"Failed to create subscription for: {endpoint}")

if __name__ == "__main__":
    main()